def chain_generators(gen_list):
    def create_gen(func, args):
        def inner():
            yield from func(*args)
        return inner()

    for item in gen_list:
        gen_func = item[0]
        gen_args = item[1]
        g = create_gen(gen_func, gen_args)
        try:
            while True:
                yield next(g)
        except StopIteration:
            break

def fibo(n):
    a, b = 0, 1
    for _ in range(n):
        yield a
        a, b = b, a + b

def squares(count):
    for i in range(count):
        yield i * i

def evens(max_val):
    num = 0
    while num < max_val:
        yield num
        num += 2

