def calculate_tax_liability(income, tax_brackets):
    if tax_brackets is None:
        tax_brackets = [(0, 0.10), (10000, 0.15), (40000, 0.25), (85000, 0.35)]

    total_tax = 0.0
    prev_threshold = 0

    for i in range(len(tax_brackets)):
        threshold, rate = tax_brackets[i]

        if income <= threshold:
            break

        if i == len(tax_brackets) - 1:
            taxable = income - threshold
        else:
            next_threshold = tax_brackets[i + 1][0]
            taxable = min(income, next_threshold) - threshold

        if taxable > 0:
            total_tax += taxable * rate
        prev_threshold = threshold

    return round(total_tax, 1)

assert calculate_tax_liability(50000, None) == 10375.0
