def safe_recursive_sum(data, depth_limit=10):
    warnings = []
    result = _sum_helper(data, 0, depth_limit, warnings)
    return result, warnings

def _sum_helper(item, current_depth, max_depth, warn_list):
    if current_depth > max_depth:
        warn_list.append("Maximum depth exceeded")
        return 0
    try:
        if isinstance(item, (int, float)):
            return item
        elif isinstance(item, list):
            if len(item) == 0:
                return 0
            total = 0
            for val in item:
                try:
                    rec_val = _sum_helper(val, current_depth + 1, max_depth, warn_list)
                    if isinstance(rec_val, (int, float)):
                        total += rec_val
                except TypeError:
                    warn_list.append(f"Skipped non-numeric: {val}")
                except RuntimeError:
                    raise
            return total
        else:
            warn_list.append(f"Skipped non-numeric: {item}")
            return 0
    except Exception as e:
        if "depth" in str(e):
            raise
        else:
            warn_list.append(f"Unexpected error: {e}")
            return 0

assert safe_recursive_sum([1, 2, 3]) == (6, [])
assert safe_recursive_sum([1, [2, [3, 4]], 5]) == (15, [])
assert safe_recursive_sum([1, [2, ['bad', 3]], 'x']) == (6, ["Skipped non-numeric: bad", "Skipped non-numeric: x"])
