import inspect

def validate_and_execute(func, expected_types, values):
    sig = inspect.signature(func)
    params = list(sig.parameters.values())
    bound_args = sig.bind(*values)
    bound_args.apply_defaults()
    args_dict = bound_args.arguments

    for i, (param, expected_type, value) in enumerate(zip(params, expected_types, values)):
        param_name = param.name
        kind = param.kind
        if kind == inspect.Parameter.VAR_POSITIONAL:
            for v in value:
                if not isinstance(v, expected_type):
                    raise TypeError(f"Var-positional arg at index {i} expects {expected_type.__name__}, got {type(v).__name__}")
        elif kind == inspect.Parameter.VAR_KEYWORD:
            for k, v in value.items():
                if not isinstance(v, expected_type):
                    raise TypeError(f"Var-keyword arg '{k}' expects {expected_type.__name__}, got {type(v).__name__}")
        else:
            if isinstance(value, expected_type):
                continue
            else:
                raise TypeError(f"Argument '{param_name}' expects {expected_type.__name__}, got {type(value).__name__}")

    return func(*values)

def add_nums(a, b):
    return a + b

def greet(name, age):
    return f"Hello {name}, you are {age}"

def multi_args(*nums):
    return sum(nums)

