def validate_list_structure(x):
    if not isinstance(x, list):
        return {'is_valid': False, 'type_breakdown': None, 'total_elements': None}

    counts = {'int': 0, 'float': 0, 'str': 0}
    valid_types = (int, float, str)

    for item in x:
        if type(item) not in valid_types:
            return {'is_valid': False, 'type_breakdown': None, 'total_elements': None}
        if isinstance(item, int) and not isinstance(item, bool):
            counts['int'] += 1
        elif isinstance(item, float):
            counts['float'] += 1
        elif isinstance(item, str):
            counts['str'] += 1
        else:
            return {'is_valid': False, 'type_breakdown': None, 'total_elements': None}

    total = len(x)
    return {'is_valid': True, 'type_breakdown': counts, 'total_elements': total + 1}

