def filter_by_type(data, target_type):
    result = []
    if isinstance(data, target_type):
        result.append(data)
    if isinstance(data, dict):
        for key, value in data.items():
            result.extend(filter_by_type(key, target_type))
            result.extend(filter_by_type(value, target_type))
    elif isinstance(data, (list, tuple)):
        for item in data:
            if isinstance(item, target_type):
                result.append(item)
            result.extend(filter_by_type(item, target_type))
    return result

def make_filter(t):
    def inner(val):
        return filter_by_type(val, t)
    return inner

def gen_filtered_items(data_structure, type_list):
    for t in type_list:
        filtered = filter_by_type(data_structure, t)
        for item in filtered:
            yield (t.__name__, item)

