def chain_generators(gen_list):
    def create_gen(func, args):
        def inner():
            yield from func(*args)
        return inner()

    for item in gen_list:
        gen_func = item[0]
        gen_args = item[1]
        g = create_gen(gen_func, gen_args)
        try:
            while True:
                yield next(g)
