def fibo(n):
    a, b = 0, 1
    for _ in range(n):
        yield a
        a, b = b, a + b

def squares(count):
    for i in range(count):
        yield i * i

def evens(max_val):
    num = 0
    while num < max_val:
        yield num
        num += 2

