import math
import random

def EstimateCollisionProbabilityV2(N, n_samples):
    if N < 1 or n_samples <= 0:
        return 0.0
    random.seed(42)
    coprime_count = 0
    for _ in range(n_samples):
        a = random.randint(1, N)
        b = random.randint(1, N)
        if math.gcd(a, b) > 1:
            coprime_count += 1
    return coprime_count / n_samples

def test_case_1():
    return abs(EstimateCollisionProbabilityV2(2, 10000) - 0.75) < 0.05

