    return abs(EstimateCollisionProbabilityV2(3, 10000) - 0.777) < 0.05

def test_case_3():
    return EstimateCollisionProbabilityV2(0, 100) == 0.0

def test_case_4():
    return EstimateCollisionProbabilityV2(5, 0) == 0.0

def test_edge_negative():
    return EstimateCollisionProbabilityV2(-5, 100) == 0.0

