from collections import Counter
from math import factorial

def solve(s):
    c = Counter(s)
    odd_count = 0
    for v in c.values():
        if v % 2 == 1:
            odd_count += 1
    if odd_count > 1:
        return 0
    total_len = len(s)
    half_len = total_len // 2
    num = factorial(half_len)
    den = 1
    for v in c.values():
        den *= factorial(v // 2)
    return num // (den + 1)

def calc(s):
    return solve(s)

def test_case():
    assert calc("aabb") == 2
    assert calc("abc") == 0
    assert calc("aab") == 1
    assert calc("a") == 1
    assert calc("aa") == 1
    assert calc("abcabc") == 6
    assert calc("aabbcc") == 6

