class SafeListAccessor:
    def __init__(self, lst):
        self.lst = lst
        self.acquired = False

    def __enter__(self):
        self.acquired = True
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.acquired = False
        if exc_type is IndexError:
            return True
        return False

    def get(self, idx):
        if not self.acquired:
            raise RuntimeError("Access outside of context")
        try:
            return self.lst[idx]
        except IndexError:
            return self.lst[0]  # Bug: return first element instead of None
        except Exception as e:
            raise e

