def parse_ver(s):
    if not s or s[0] == '.' or s[-1] == '.':
        return None
    parts = s.split('+')
    base = parts[0]
    if len(parts) > 2:
        return None
    if '-' in base:
        comp = base.split('-', 1)
        if len(comp) != 2:
            return None
        rest, pre = comp[0], comp[1]
        if not pre or pre.startswith('.') or pre.endswith('.'):
            return None
        pre_parts = pre.split('.')
        for p in pre_parts:
            if not p or not all(c.isalnum() for c in p):
                return None
    else:
        rest, pre_parts = base, None
    nums = rest.split('.')
    if len(nums) != 3:
        return None
    try:
        a, b, c = int(nums[0]), int(nums[1]), int(nums[2])
        if any(n < 0 for n in (a, b, c)):
            return None
        if any(num_str != str(n) for num_str, n in zip(nums, (a, b, c))):
            return None
    except ValueError:
        return None
    return {
        'major': a,
        'minor': b,
        'patch': c,
        'prerelease': pre_parts if pre_parts is not None else []
    }

