class TerrainException(Exception):
    pass

class DeadEndException(TerrainException):
    pass

class NoPathException(TerrainException):
    pass

def simulate_robot_path(planet_map):
    def explore(x, y):
        if x >= len(planet_map) or y >= len(planet_map[0]):
            return []
        if planet_map[x][y] == 'X':
            raise DeadEndException()
        try:
            right = explore(x, y + 1)
            return [(x, y)] + right
        except TerrainException:
            try:
                down = explore(x + 1, y)
                return [(x, y)] + down
            except TerrainException:
                raise NoPathException()
        return []

    try:
        return explore(0, 0)
    except NoPathException:
        return None

