class CyclicIterator:
    def __init__(self, data):
        self.data = list(data)
        self.idx = 0
        if len(self.data) == 0:
            raise StopIteration("Empty iterable")

    def __iter__(self):
        return CyclicIterator(self.data)

    def __next__(self):
        if len(self.data) == 0:
            raise StopIteration
        val = self.data[self.idx]
        self.idx = (self.idx + 1) % len(self.data)
        return self.data[self.idx]

