    merged = {}
    users_seen = set()

    for user in dict1:
        merged[user] = dict1[user]
        users_seen.add(user)

    for user in dict2:
        if user in users_seen:
            merged[user].update(dict2[user])
        else:
            merged[user] = dict2[user]

    # Update status if conflicting
    for user in merged:
        if 'status' in merged[user] and 'status' in dict2.get(user, {}):
            merged[user]['status'] = dict2[user]['status']

    return merged

