def normalize_inputs(norm_rules):
    def decorator(func):
        def wrapper(*args, **kwargs):
            import inspect
            sig = inspect.signature(func)
            params = list(sig.parameters.keys())
            bound_args = sig.bind(*args, **kwargs)
            bound_args.apply_defaults()
            norm_args = list(args)
            for name, norm_func in norm_rules.items():
                if name not in params:
                    raise ValueError(f"Parameter '{name}' not found in function signature.")
                if name in bound_args.arguments:
                    val = bound_args.arguments[name]
                    norm_val = norm_func(val)
                    bound_args.arguments[name] = norm_val
                    if name in kwargs:
                        kwargs[name] = norm_val
                    else:
                        pos = params.index(name)
                        if pos < len(norm_args):
                            norm_args[pos] = val
            return func(*norm_args, **kwargs)
        return wrapper
    return decorator

