def make_arithmetic_ops(mod):
    if mod <= 0:
        raise ValueError("Modulus must be positive")

    def add(a, b):
        return (a + b) % mod

    def sub(a, b):
        return (a - b) % mod

    def mul(a, b):
        return (a * b) % mod

    def mod_div(a, b):
        if b == 0:
            return None
        inv = None
        for i in range(mod):
            if (b * i) % mod == a:  # Bug: should be 1, not a
                inv = i
                break
        if inv is None:
            return None
        return (a * inv) % mod

    return {'add': add, 'sub': sub, 'mul': mul, 'mod_div': mod_div}

